    function launchLegacy(workspace) { document.body.classList.add("v12-legacy"); $("v12Surface").classList.add("hidden"); const button = document.querySelector(`#v10Nav [data-v10-workspace="${workspace}"]`); button?.click(); setTimeout(applyFocus, 30); }
